import tensorflow as tf
import pandas as pd
import numpy as np
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import os
from PIL import Image
import hashlib
import json
from datetime import datetime
import re

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'uploads'
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024  # 16MB max file size

# Create upload directory
os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)

# Model configuration
IMG_SIZE = 224
BATCH_SIZE = 32
EPOCHS = 10

# Security controls
ALLOWED_EXTENSIONS = {'csv', 'jpg', 'jpeg', 'png'}
MAX_FILE_SIZE = 16 * 1024 * 1024  # 16MB
MAX_TRAINING_EXAMPLES = 10000
TRAINING_LOG = 'training_log.json'

# Initialize model
model = None
class_names = []

def validate_file_extension(filename):
    """Validate file extension"""
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def validate_file_size(file):
    """Validate file size"""
    file.seek(0, os.SEEK_END)
    file_size = file.tell()
    file.seek(0)
    return file_size <= MAX_FILE_SIZE

def sanitize_filename(filename):
    """Sanitize filename to prevent path traversal"""
    filename = secure_filename(filename)
    # Remove any path components
    filename = os.path.basename(filename)
    # Remove any non-alphanumeric characters except dots and underscores
    filename = re.sub(r'[^a-zA-Z0-9._-]', '', filename)
    return filename

def validate_csv_data(df):
    """Validate CSV data structure"""
    if df.empty:
        raise ValueError("CSV file is empty")
    
    # Check for required columns
    if 'image_path' not in df.columns:
        raise ValueError("CSV must contain 'image_path' column")
    
    # Validate data types
    if not pd.api.types.is_string_dtype(df['image_path']):
        raise ValueError("image_path column must contain strings")
    
    # Limit rows to prevent memory issues
    if len(df) > MAX_TRAINING_EXAMPLES:
        df = df.head(MAX_TRAINING_EXAMPLES)
    
    return df

def load_and_preprocess_image(image_path):
    """Load and preprocess image"""
    try:
        image = tf.io.read_file(image_path)
        image = tf.image.decode_image(image, channels=3)
        image = tf.image.resize(image, [IMG_SIZE, IMG_SIZE])
        image = tf.cast(image, tf.float32) / 255.0
        return image
    except Exception as e:
        raise ValueError(f"Error processing image {image_path}: {str(e)}")

def create_model(num_classes):
    """Create and compile model"""
    model = tf.keras.Sequential([
        tf.keras.layers.Conv2D(32, (3, 3), activation='relu', input_shape=(IMG_SIZE, IMG_SIZE, 3)),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
        tf.keras.layers.Flatten(),
        tf.keras.layers.Dense(64, activation='relu'),
        tf.keras.layers.Dense(num_classes, activation='softmax')
    ])
    
    model.compile(optimizer='adam',
                  loss='sparse_categorical_crossentropy',
                  metrics=['accuracy'])
    
    return model

def load_training_data(csv_path):
    """Load training data from CSV"""
    try:
        df = pd.read_csv(csv_path)
        df = validate_csv_data(df)
        
        # Get unique classes from image paths
        classes = set()
        image_paths = []
        labels = []
        
        for _, row in df.iterrows():
            image_path = row['image_path']
            if not os.path.exists(image_path):
                continue
                
            # Extract class from path or use filename
            class_name = os.path.basename(os.path.dirname(image_path))
            if not class_name:
                class_name = os.path.splitext(os.path.basename(image_path))[0]
            
            classes.add(class_name)
            image_paths.append(image_path)
            labels.append(class_name)
        
        class_names = sorted(list(classes))
        label_map = {name: idx for idx, name in enumerate(class_names)}
        numeric_labels = [label_map[label] for label in labels]
        
        return image_paths, numeric_labels, class_names
        
    except Exception as e:
        raise ValueError(f"Error loading training data: {str(e)}")

def train_model(image_paths, labels, class_names):
    """Train the model"""
    global model
    
    # Create model
    model = create_model(len(class_names))
    
    # Create dataset
    dataset = tf.data.Dataset.from_tensor_slices((image_paths, labels))
    dataset = dataset.map(lambda x, y: (load_and_preprocess_image(x), y))
    dataset = dataset.batch(BATCH_SIZE)
    
    # Train model
    history = model.fit(dataset, epochs=EPOCHS, verbose=0)
    
    return history

@app.route('/upload', methods=['POST'])
def upload_file():
    """Handle file upload"""
    try:
        # Check if file is provided
        if 'file' not in request.files:
            return jsonify({'error': 'No file provided'}), 400
        
        file = request.files['file']
        
        # Validate file
        if file.filename == '':
            return jsonify({'error': 'No file selected'}), 400
        
        if not validate_file_extension(file.filename):
            return jsonify({'error': 'Invalid file type'}), 400
        
        if not validate_file_size(file):
            return jsonify({'error': 'File too large'}), 400
        
        # Save file
        filename = sanitize_filename(file.filename)
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(file_path)
        
        # Process based on file type
        if filename.endswith('.csv'):
            # Handle CSV upload for training data
            try:
                image_paths, labels, class_names = load_training_data(file_path)
                history = train_model(image_paths, labels, class_names)
                
                # Log training
                log_entry = {
                    'timestamp': datetime.now().isoformat(),
                    'file': filename,
                    'samples': len(image_paths),
                    'classes': len(class_names),
                    'accuracy': float(max(history.history['accuracy']))
                }
                
                # Append to log
                try:
                    with open(TRAINING_LOG, 'r') as f:
                        log_data = json.load(f)
                except:
                    log_data = []
                
                log_data.append(log_entry)
                
                with open(TRAINING_LOG, 'w') as f:
                    json.dump(log_data, f)
                
                return jsonify({
                    'message': 'Training data processed successfully',
                    'samples': len(image_paths),
                    'classes': len(class_names),
                    'accuracy': float(max(history.history['accuracy']))
                })
                
            except Exception as e:
                return jsonify({'error': str(e)}), 400
        
        else:
            # Handle image upload for contribution
            return jsonify({
                'message': 'Image uploaded successfully',
                'file': filename
            })
            
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/contribute', methods=['POST'])
def contribute_example():
    """Allow users to contribute training examples"""
    try:
        # Validate request data
        if not request.json:
            return jsonify({'error': 'Invalid JSON data'}), 400
        
        data = request.json
        
        # Validate required fields
        required_fields = ['image_path', 'label']
        for field in required_fields:
            if field not in data:
                return jsonify({'error': f'Missing required field: {field}'}), 400
        
        # Validate image path
        image_path = data['image_path']
        if not os.path.exists(image_path):
            return jsonify({'error': 'Image file not found'}), 400
        
        # Validate label
        label = data['label']
        if not isinstance(label, str) or not label.strip():
            return jsonify({'error': 'Invalid label'}), 400
        
        # Add to training data
        # In a real implementation, this would update the model
        return jsonify({
            'message': 'Training example contributed successfully',
            'label': label
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/predict', methods=['POST'])
def predict():
    """Make prediction on uploaded image"""
    try:
        if 'image' not in request.files:
            return jsonify({'error': 'No image provided'}), 400
        
        file = request.files['image']
        
        if file.filename == '':
            return jsonify({'error': 'No image selected'}), 400
        
        # Save image temporarily
        filename = sanitize_filename(file.filename)
        temp_path = os.path.join(app.config['UPLOAD_FOLDER'], 'temp_' + filename)
        file.save(temp_path)
        
        # Load and preprocess image
        image = load_and_preprocess_image(temp_path)
        image = tf.expand_dims(image, 0)  # Add batch dimension
        
        # Make prediction
        if model is None:
            return jsonify({'error': 'Model not trained yet'}), 400
        
        predictions = model.predict(image)
        predicted_class = np.argmax(predictions[0])
        confidence = float(predictions[0][predicted_class])
        
        # Clean up
        os.remove(temp_path)
        
        return jsonify({
            'predicted_class': class_names[predicted_class] if class_names else str(predicted_class),
            'confidence': confidence
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

